    function toggle() {
        isOpen = !isOpen;
    }

    function selectLanguage(code) {
        if (isSupported(code)) {
            $currentLocale = code;
            isOpen = false;
        }
    }

    function handleWindowClick(event) {
        if (isOpen && selectContainer && !selectContainer.contains(event.target)) {
            isOpen = false;
        }
    }

    $: currentLabel =
        languages.find((l) => l.code === $currentLocale)?.label || "Language";
</script>

<svelte:window on:click={handleWindowClick} />

<div class="relative w-full text-white font-sans select-none"
bind:this={selectContainer}>
{#if isOpen}
    <div
        transition:slide={{ duration: 200 }}
        class="absolute bottom-full mb-2 w-full bg-[#2A2A2A] border border-gray-700 dark:border-[#303030] rounded-md overflow-hidden shadow-xl z-50 max-h-60 overflow-y-auto custom-scrollbar"
    >
        {#each languages as lang}
            <button
                class="w-full text-left px-4 py-3 hover:bg-white/10 transition-colors flex items-center justify-between
                {lang.code === $currentLocale
                    ? 'text-yellow-400 bg-white/5'
                    : 'text-gray-300'}
                {!isSupported(lang.code)
                    ? 'opacity-50 cursor-not-allowed'
                    : ''}"
                on:click={() => selectLanguage(lang.code)}
            >
                <div class="flex items-center gap-3">
                    <div class="w-5 h-5 flex-shrink-0 content-center">
                        <Icons name={lang.code} class="w-full h-full" />
                    </div>
                    
                    <span>{lang.label}</span>
                </div>

                {#if lang.code === $currentLocale}
                    <svg
                        class="w-4 h-4 ml-2 flex-shrink-0"
                        fill="none"
                        stroke="currentColor"
                        viewBox="0 0 24 24"
                    >
                        <path
                            stroke-linecap="round"
                            stroke-linejoin="round"
                            stroke-width="2"
                            d="M5 13l4 4L19 7"
                        ></path>
                    </svg>
                {/if}
            </button>
        {/each}
    </div>
{/if}


    <button
        on:click={toggle}
        class="relative w-full h-14 bg-[#3A3A3A] hover:bg-[#444] transition-colors flex items-center overflow-hidden group"
    >
        <div
            class="absolute right-0 top-0 h-full pointer-events-none mix-blend-overlay opacity-30"
        >
            {@html topoPattern}
        </div>
        <div class="absolute left-0 top-0 bottom-0 w-1 bg-[#FFE145] z-10"></div>
        <div class="relative z-10 flex items-center w-full px-5 content-center">
            <div class="mr-4 text-white">
                <Icons name={$currentLocale} class="w-6 h-6" />
            </div>

            <span class="text-lg font-medium flex-grow text-left pt-0.5 justify-center">
                {currentLabel}
            </span>

            <div
                class="transition-transform duration-200 {isOpen
                    ? 'rotate-180'
                    : ''}"
            >
                <svg
                    width="20"
                    height="20"
                    viewBox="0 0 24 24"
                    fill="none"
                    stroke="currentColor"
                    stroke-width="2"
                    stroke-linecap="round"
                    stroke-linejoin="round"
                >
                    <polyline points="18 15 12 9 6 15"></polyline>
                </svg>
            </div>
        </div>
    </button>
</div>

<style>
    .custom-scrollbar::-webkit-scrollbar {
        width: 6px;
    }
    .custom-scrollbar::-webkit-scrollbar-track {
        background: #2a2a2a;
    }
    .custom-scrollbar::-webkit-scrollbar-thumb {
        background: #555;
        border-radius: 3px;
    }
    .custom-scrollbar::-webkit-scrollbar-thumb:hover {
        background: #777;
    }
</style>